const isEnrichment = msg.payload.isEnrichment;
const skipped = msg.payload.skipped;

if (skipped) {
    msg.title = `ChassisShield Lead (Step 2 Skipped): ${msg.payload.email}`;
    msg.payload = `Email: ${msg.payload.email}\n\nUser skipped profile enrichment (Step 2). Opportunity marked 'Skipped Profile' (Enrichment Pending) with a follow-up task to reach out manually.`;
} else if (isEnrichment) {
    msg.title = `ChassisShield Lead Enriched: ${msg.payload.name || msg.payload.email}`;
    msg.payload = `Name: ${msg.payload.name || 'Not specified'}\nEmail: ${msg.payload.email}\nVehicle: ${msg.payload.carType || 'Not specified'}\nLocation: ${msg.payload.location || 'Not specified'}\nComments: ${msg.payload.comments || 'None'}`;
} else {
    msg.title = `New ChassisShield Lead: ${msg.payload.email}`;
    msg.payload = `New waitlist signup:\nEmail: ${msg.payload.email}\nLocation: ${msg.payload.location || 'Not specified'}\n\nAwaiting Step 2 details.`;
}
msg.priority = 6;
return msg;

msg.originalPayload = msg.payload; // Save for Opportunity/Note creation later
const name = (msg.payload.name || '').trim();
const email = (msg.payload.email || '').trim().toLowerCase();

const nameParts = name.split(' ');
const firstName = nameParts[0] || 'Waitlist';
const lastName = nameParts.slice(1).join(' ') || 'Lead';

msg.lead = {
    firstName: firstName,
    lastName: lastName,
    email: email
};
msg.jobTitle = "Chassis Shield Lead";
msg.twentyToken = env.get("CHASSISSHIELD_TWENTY_TOKEN");
msg.twentyHost = "chassisshield.localhost:3000";

return msg;

const person = msg.payload && msg.payload.data && (msg.payload.data.createPerson || msg.payload.data.updatePerson);
const personId = person ? person.id : '';
msg.payload = {
    success: true,
    twentyUrl: personId ? `https://chassisshield.crm.cosmoslab.dev/object/person/${personId}` : ''
};
msg.statusCode = 200;
msg.headers = {
    'Content-Type': 'application/json'
};
return msg;

delete msg.res;
delete msg.req;

const person = msg.payload && msg.payload.data && (msg.payload.data.createPerson || msg.payload.data.updatePerson);
const personId = person ? person.id : '';
msg.personId = personId;

if (!personId) {
    node.warn("ChassisShield: Person create/update failed - " + JSON.stringify(msg.payload));

    const lead = msg.originalPayload || {};
    msg.title = "\u26a0\ufe0f ChassisShield CRM Sync FAILED";
    msg.priority = 9;
    msg.payload = `Lead (${lead.email || 'no email'}, ${lead.name || 'Unknown'}) did NOT sync to CRM.\n\nTwenty API response:\n${JSON.stringify(msg.payload)}`;
    return [null, msg]; // Stop the CRM chain, send a Gotify alert instead
}

msg.method = "GET";
msg.url = `${env.get("TWENTY_BASE_URL")}/rest/opportunities?filter=pointOfContact.id[eq]:${encodeURIComponent(personId)}`;

return [msg, null];

const searchData = msg.payload;
const existing = searchData && searchData.data && searchData.data.opportunities && searchData.data.opportunities[0];
msg.existingOpportunityId = existing ? existing.id : '';

const data = msg.originalPayload;
const isEnrichment = !!data.isEnrichment;
const skipped = !!data.skipped;
const displayName = data.name || data.email;


if (!isEnrichment) {
    // Step 1: create the Opportunity right away, marked incomplete.
    // If one already exists (e.g. a retried Step 1 call), there's nothing to do.
    if (msg.existingOpportunityId) {
        return null;
    }
    msg.opportunityCase = 'incomplete';
    msg.method = "POST";
    msg.url = env.get("TWENTY_BASE_URL") + "/rest/opportunities";
    msg.payload = {
        name: `ChassisShield Waitlist (Profile Incomplete): ${displayName}`,
        stage: "SCREENING",
        pointOfContactId: msg.personId
    };
} else if (skipped) {
    msg.opportunityCase = 'skipped';
    msg.payload = {
        name: `ChassisShield Waitlist (Skipped Profile): ${displayName}`,
        stage: "SCREENING"
    };
    if (msg.existingOpportunityId) {
        msg.method = "PATCH";
        msg.url = `${env.get("TWENTY_BASE_URL")}/rest/opportunities/${msg.existingOpportunityId}`;
    } else {
        msg.method = "POST";
        msg.url = env.get("TWENTY_BASE_URL") + "/rest/opportunities";
        msg.payload.pointOfContactId = msg.personId;
    }
} else {
    msg.opportunityCase = 'enriched';
    msg.payload = {
        name: `ChassisShield Waitlist: ${displayName}`,
        stage: "MEETING"
    };
    if (msg.existingOpportunityId) {
        msg.method = "PATCH";
        msg.url = `${env.get("TWENTY_BASE_URL")}/rest/opportunities/${msg.existingOpportunityId}`;
    } else {
        msg.method = "POST";
        msg.url = env.get("TWENTY_BASE_URL") + "/rest/opportunities";
        msg.payload.pointOfContactId = msg.personId;
    }
}

return msg;

const data = msg.originalPayload;

let markdown = `**Vehicle:** ${data.carType || 'Not specified'}\n`;
markdown += `**Location:** ${data.location || 'Not specified'}\n\n`;
if (data.comments) {
    markdown += `**Comments:**\n${data.comments}\n`;
}

msg.noteTitle = "Chassis Shield Waitlist Enrichment";
msg.noteMarkdown = markdown;
msg.twentyToken = env.get("CHASSISSHIELD_TWENTY_TOKEN");
msg.twentyHost = "chassisshield.localhost:3000";

return msg;

msg.title = `New CurbClass Lead: ${msg.payload.name || 'New Lead'}`;
msg.priority = 6;
const product = msg.payload.product || 'General inquiry';
const scheduleMatch = product.match(/Schedule:\s*([^|]+)/);
const scheduleLine = scheduleMatch ? `\nSchedule: ${scheduleMatch[1].trim()}` : '';
msg.payload = `Name: ${msg.payload.name}\nEmail: ${msg.payload.email}\nPhone: ${msg.payload.phone}\nProduct: ${product}\nMessage: ${msg.payload.message || 'No message provided.'}${scheduleLine}`;
return msg;

msg.originalPayload = msg.payload; // Save for Note creation later
const name = (msg.payload.name || '').trim();
const email = (msg.payload.email || '').trim().toLowerCase();
let phone = (msg.payload.phone || '').trim();

// Normalize and validate phone to E.164
let validPhone = null;
const cleanPhone = phone.replace(/\D/g, '');
if (cleanPhone.length === 10) {
    validPhone = '+1' + cleanPhone;
} else if (cleanPhone.length > 10) {
    validPhone = phone.startsWith('+') ? phone : '+' + cleanPhone;
}

const nameParts = name.split(' ');
const firstName = nameParts[0] || '';
const lastName = nameParts.slice(1).join(' ') || 'Lead';

msg.lead = {
    firstName: firstName,
    lastName: lastName,
    email: email,
    phone: validPhone
};
msg.jobTitle = "Curb Class Lead";
msg.twentyToken = env.get("CURBCLASS_TWENTY_TOKEN");
msg.twentyHost = "curbclass.localhost:3000";

return msg;

const person = msg.payload && msg.payload.data && (msg.payload.data.createPerson || msg.payload.data.updatePerson);
const personId = person ? person.id : '';
msg.payload = {
    success: true,
    twentyUrl: personId ? `https://crm.cosmoslab.dev/object/person/${personId}` : ''
};
msg.statusCode = 200;
msg.headers = {
    'Content-Type': 'application/json'
};
return msg;

delete msg.res;
delete msg.req;

const person = msg.payload && msg.payload.data && (msg.payload.data.createPerson || msg.payload.data.updatePerson);
const personId = person ? person.id : '';
msg.personId = personId;

if (!personId) {
    node.warn("CurbClass: Person create/update failed - " + JSON.stringify(msg.payload));

    const lead = msg.originalPayload || {};
    msg.title = "\u26a0\ufe0f CurbClass CRM Sync FAILED";
    msg.priority = 9;
    msg.payload = `Lead from ${lead.name || 'Unknown'} (${lead.email || 'no email'}) did NOT sync to CRM.\n\nTwenty API response:\n${JSON.stringify(msg.payload)}`;
    return [null, msg]; // Stop the CRM chain, send a Gotify alert instead
}

let intakeDetails = `Product: ${msg.originalPayload.product || 'General inquiry'}\n`;
if (msg.originalPayload.message) {
    intakeDetails += `\nMessage:\n${msg.originalPayload.message}\n`;
}
if (msg.originalPayload.imageUrls && msg.originalPayload.imageUrls.length > 0) {
    intakeDetails += `\nProperty Photos:\n`;
    msg.originalPayload.imageUrls.forEach((url, i) => {
        intakeDetails += `- Photo ${i + 1}: ${url}\n`;
    });
}

msg.method = "POST";
msg.url = env.get("TWENTY_BASE_URL") + "/rest/opportunities";
msg.payload = {
    name: "CurbClass: " + (msg.originalPayload.name || "New Lead"),
    stage: "NEW",
    pointOfContactId: personId,
    intakeDetails: intakeDetails
};

return [msg, null];

const opp = msg.payload && msg.payload.data && msg.payload.data.createOpportunity;
const oppId = opp ? opp.id : '';
msg.opportunityId = oppId;

if (!oppId) {
    node.warn("CurbClass: Opportunity creation failed. payload=" + JSON.stringify(msg.payload));
}

if (!msg.personId || (!msg.originalPayload.message && (!msg.originalPayload.imageUrls || msg.originalPayload.imageUrls.length === 0))) {
    return null; // Skip if nothing to record
}

let markdown = `**Product:** ${msg.originalPayload.product || 'General inquiry'}\n\n`;
if (msg.originalPayload.message) {
    markdown += `**Message:**\n${msg.originalPayload.message}\n\n`;
}
if (msg.originalPayload.imageUrls && msg.originalPayload.imageUrls.length > 0) {
    markdown += `**Property Photos:**\n`;
    msg.originalPayload.imageUrls.forEach((url, i) => {
        markdown += `- [Photo ${i + 1}](${url})\n`;
    });
}

msg.noteTitle = "CurbClass Inquiry Details";
msg.noteMarkdown = markdown;
msg.twentyToken = env.get("CURBCLASS_TWENTY_TOKEN");
msg.twentyHost = "curbclass.localhost:3000";

return msg;

const opp = msg.payload && msg.payload.data && msg.payload.data.createOpportunity;
const oppId = opp ? opp.id : '';

if (!oppId || !msg.originalPayload.imageUrls || msg.originalPayload.imageUrls.length === 0) {
    return null;
}

const token = env.get("CURBCLASS_TWENTY_TOKEN");
const fieldMetadataId = "951c6783-41fd-4f2c-ba4f-f250fcb0fb9e"; // CurbClass file field metadata ID

(async () => {
    try {
        for (let i = 0; i < msg.originalPayload.imageUrls.length; i++) {
            const url = msg.originalPayload.imageUrls[i];
            const filename = url.substring(url.lastIndexOf('/') + 1);

            // 1. Fetch the image from local server / cosmoslab.dev
            const response = await axios.get(url, { responseType: 'arraybuffer' });
            const buffer = Buffer.from(response.data);

            // 2. Upload to Twenty Metadata endpoint
            const form = new FormData();
            form.append('operations', JSON.stringify({
                operationName: "UploadFilesFieldFile",
                variables: {
                    file: null,
                    fieldMetadataId: fieldMetadataId
                },
                query: "mutation UploadFilesFieldFile($file: Upload!, $fieldMetadataId: String!) { uploadFilesFieldFile(file: $file, fieldMetadataId: $fieldMetadataId) { id } }"
            }));
            form.append('map', JSON.stringify({
                "1": ["variables.file"]
            }));
            form.append('1', buffer, { filename: filename, contentType: 'image/jpeg' });

            const uploadRes = await axios.post(env.get("TWENTY_BASE_URL") + "/metadata", form, {
                headers: {
                    ...form.getHeaders(),
                    'Authorization': `Bearer ${token}`,
                    'Host': 'curbclass.localhost:3000'
                }
            });

            const fileId = uploadRes.data && uploadRes.data.data && uploadRes.data.data.uploadFilesFieldFile && uploadRes.data.data.uploadFilesFieldFile.id;
            if (!fileId) {
                node.warn("CurbClass: Did not receive fileId for: " + filename);
                continue;
            }

            // 3. Create Attachment record via REST
            const attachRes = await axios.post(env.get("TWENTY_BASE_URL") + "/rest/attachments", {
                name: filename,
                fullPath: url,
                targetOpportunityId: oppId,
                fileCategory: "IMAGE",
                file: [
                    {
                        fileId: fileId,
                        label: filename
                    }
                ]
            }, {
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Host': 'curbclass.localhost:3000',
                    'Content-Type': 'application/json'
                }
            });

            if (attachRes.status !== 201) {
                node.warn("CurbClass: Failed to create attachment for: " + filename + " status: " + attachRes.status);
            }
        }
    } catch (err) {
        node.warn("CurbClass: Error in prepare attachments async function: " + err.message);
    }
})();

return null;

const err = msg.error || {};
const src = err.source ? ` [source: ${err.source.name || err.source.id}]` : '';
const errText = (err.message || String(err)) + src;

// If the HTTP response was already cleared (background CRM path), just log — don't try to respond.
// IMPORTANT: never pass msg to node.error here; that re-routes through catch and causes a loop.
if (!msg.res) {
    node.warn("Background CRM error (ignored): " + errText);
    return null;
}

node.warn("Lead processing error (will 500): " + errText);

msg.statusCode = 500;
msg.payload = { success: false, error: "Failed to process lead." };
msg.headers = { "Content-Type": "application/json" };
return msg;

if (msg.noteResult && !msg.noteResult.success) {
    node.warn("ChassisShield: Note creation/link failed - " + JSON.stringify(msg.noteResult.error || msg.noteResult.details));
}
return null;

const data = msg.originalPayload;

msg.taskTitle = `Follow up: ${data.name || 'Waitlist Lead'} (Chassis Shield enrichment)`;
msg.taskMarkdown = `**Vehicle:** ${data.carType || 'Not specified'}\n**Location:** ${data.location || 'Not specified'}\n\nReview enrichment details and reach out within 24 hours.`;
msg.twentyToken = env.get("CHASSISSHIELD_TWENTY_TOKEN");
msg.twentyHost = "chassisshield.localhost:3000";

return msg;

if (msg.taskResult && !msg.taskResult.success) {
    node.warn("ChassisShield: Task creation/link failed - " + JSON.stringify(msg.taskResult.error || msg.taskResult.details));
}
return null;

if (msg.noteResult && !msg.noteResult.success) {
    node.warn("CurbClass: Note creation/link failed - " + JSON.stringify(msg.noteResult.error || msg.noteResult.details));
}
return null;

const opp = msg.payload && msg.payload.data && msg.payload.data.createOpportunity;
const oppId = opp ? opp.id : '';
msg.opportunityId = oppId;

if (!oppId) {
    // Already warned by the Note-preparation branch
    return null;
}

const data = msg.originalPayload;
const hasPhotos = data.imageUrls && data.imageUrls.length > 0;

msg.taskTitle = `Follow up: ${data.name || 'New Lead'} - ${data.product || 'General inquiry'}`;
msg.taskMarkdown = `**Phone:** ${data.phone || 'Not specified'}\n**Product:** ${data.product || 'General inquiry'}\n**Photos attached:** ${hasPhotos ? 'Yes (' + data.imageUrls.length + ')' : 'No'}\n\n${data.message ? '**Message:**\n' + data.message + '\n\n' : ''}Prepare quote and respond within 24 hours.`;
msg.twentyToken = env.get("CURBCLASS_TWENTY_TOKEN");
msg.twentyHost = "curbclass.localhost:3000";

return msg;

const event = msg.payload.event;
const data = msg.payload.data;
const token = env.get("CURBCLASS_TWENTY_TOKEN");

if (!event || !data) {
    msg.payload = { success: false, error: "Invalid payload" };
    msg.statusCode = 400;
    return [msg, null];
}

// Respond 200 immediately to Invoice Ninja to acknowledge receipt
const responseMsg = {
    payload: { success: true },
    statusCode: 200,
    headers: { "Content-Type": "application/json" },
    req: msg.req,
    res: msg.res
};

// For invoice/quote events, require client_id and status_id to proceed
if (/^(create|update)_(invoice|quote)$/i.test(event)) {
    if (data.client_id === undefined || data.status_id === undefined) {
        node.warn(`CurbClass: Ignoring ${event} webhook missing client_id/status_id`);
        return [responseMsg, null];
    }
}

// Forward to background processing
const jobMsg = {
    token: token,
    ninjaEvent: event,
    ninjaData: data
};

return [responseMsg, jobMsg];

const client = msg.ninjaData;
const clientId = client.hashed_id || client.id;
const primaryContact = client.contacts && client.contacts[0];
const email = primaryContact ? (primaryContact.email || "").trim().toLowerCase() : "";
const name = client.name || (primaryContact ? `${primaryContact.first_name} ${primaryContact.last_name}` : "");

if (!email) {
    return null; // Can not map without email
}

const nameParts = name.trim().split(" ");
const firstName = nameParts[0] || "";
const lastName = nameParts.slice(1).join(" ") || "Client";

msg.clientInfo = {
    id: clientId,
    firstName: firstName,
    lastName: lastName,
    email: email
};

msg.method = "GET";
msg.url = `${env.get("TWENTY_BASE_URL")}/rest/people?filter=emails.primaryEmail[eq]:${encodeURIComponent(email)}`;
msg.headers = {
    "Authorization": "Bearer " + msg.token,
    "Host": "curbclass.localhost:3000"
};

return msg;

const searchData = msg.payload;
const existingPerson = searchData.data && searchData.data.people && searchData.data.people[0];
let url, method, body;

if (existingPerson) {
    url = `${env.get("TWENTY_BASE_URL")}/rest/people/${existingPerson.id}`;
    method = "PATCH";
    body = {
        invoiceNinjaClientId: msg.clientInfo.id
    };
} else {
    url = env.get("TWENTY_BASE_URL") + "/rest/people";
    method = "POST";
    body = {
        name: {
            firstName: msg.clientInfo.firstName,
            lastName: msg.clientInfo.lastName
        },
        emails: {
            primaryEmail: msg.clientInfo.email
        },
        jobTitle: "Curb Class Client",
        invoiceNinjaClientId: msg.clientInfo.id
    };
}

msg.method = method;
msg.url = url;
msg.payload = body;
msg.headers = {
    "Authorization": "Bearer " + msg.token,
    "Host": "curbclass.localhost:3000",
    "Content-Type": "application/json"
};

return msg;

const invoice = msg.ninjaData;
const clientHashedId = invoice.client_id;
const invoiceStatusId = invoice.status_id;
const invoiceAmount = invoice.amount;

// We need to find the person in Twenty who matches clientHashedId
msg.invoiceInfo = {
    statusId: invoiceStatusId,
    amount: invoiceAmount,
    balance: invoice.balance,
    number: invoice.number,
    invoiceId: invoice.id || invoice.hashed_id,
    clientHashedId: clientHashedId
};

msg.method = "GET";
msg.url = `${env.get("TWENTY_BASE_URL")}/rest/people?filter=invoiceNinjaClientId[eq]:${encodeURIComponent(clientHashedId)}`;
msg.headers = {
    "Authorization": "Bearer " + msg.token,
    "Host": "curbclass.localhost:3000"
};

return msg;

const searchData = msg.payload;
const person = searchData.data && searchData.data.people && searchData.data.people[0];
if (!person) {
    node.warn("CurbClass: Could not find Person in Twenty with Client ID: " + msg.invoiceInfo.clientHashedId);
    return null;
}

msg.personId = person.id;

// Next, find the latest Opportunity for this Person to update its stage
msg.method = "GET";
msg.url = `${env.get("TWENTY_BASE_URL")}/rest/opportunities?filter=pointOfContactId[eq]:${encodeURIComponent(person.id)}`;
msg.headers = {
    "Authorization": "Bearer " + msg.token,
    "Host": "curbclass.localhost:3000"
};

return msg;

const searchData = msg.payload;
const opportunities = searchData.data && searchData.data.opportunities;
if (!opportunities || opportunities.length === 0) {
    node.warn("CurbClass: No Opportunity found for Person ID: " + msg.personId);
    return null;
}

const invoiceId = String(msg.invoiceInfo.invoiceId);

// Exact-match: find an opportunity that already has this invoice ID in invoiceNinjaRefs
const exactMatch = opportunities.find(o => {
    try {
        const refs = o.invoiceNinjaRefs ? JSON.parse(o.invoiceNinjaRefs) : [];
        return refs.includes(invoiceId);
    } catch (e) { return false; }
});

let opp;
let needsWriteback = false;

if (exactMatch) {
    opp = exactMatch;
} else {
    // Heuristic fallback (first-sighting): prefer open, most recently updated
    const openOpps = opportunities.filter(o => o.stage !== "CUSTOMER");
    const candidates = openOpps.length > 0 ? openOpps : opportunities;
    candidates.sort((a, b) => new Date(b.updatedAt) - new Date(a.updatedAt));
    opp = candidates[0];
    if (openOpps.length > 1) {
        node.warn(`CurbClass: Person ${msg.personId} has ${openOpps.length} open opportunities; picked most recently updated (${opp.id}) for invoice ${invoiceId}.`);
    }
    needsWriteback = true;
}

msg.opportunityId = opp.id;

// Status IDs in Invoice Ninja: 1=Draft, 2=Sent, 3=Viewed, 4=Paid, etc.
const ninjaStatus = msg.invoiceInfo.statusId;
let stage = opp.stage;
if (ninjaStatus === "4" || ninjaStatus === 4) {
    stage = "CUSTOMER";
} else if (ninjaStatus === "2" || ninjaStatus === 2 || ninjaStatus === "3" || ninjaStatus === 3) {
    stage = "PROPOSAL";
}

msg.method = "PATCH";
msg.url = `${env.get("TWENTY_BASE_URL")}/rest/opportunities/${opp.id}`;
msg.payload = { stage: stage };

// Writeback: add invoiceId to invoiceNinjaRefs if this is the first sighting
if (needsWriteback) {
    try {
        const refs = opp.invoiceNinjaRefs ? JSON.parse(opp.invoiceNinjaRefs) : [];
        if (!refs.includes(invoiceId)) {
            refs.push(invoiceId);
            msg.payload.invoiceNinjaRefs = JSON.stringify(refs);
        }
    } catch (e) {
        msg.payload.invoiceNinjaRefs = JSON.stringify([invoiceId]);
    }
}

msg.headers = {
    "Authorization": "Bearer " + msg.token,
    "Host": "curbclass.localhost:3000",
    "Content-Type": "application/json"
};

return msg;

delete msg.res;
delete msg.req;

const person = msg.payload && msg.payload.data && (msg.payload.data.createPerson || msg.payload.data.updatePerson);
if (!person) {
    return null;
}

const email = person.emails ? (person.emails.primaryEmail || '') : '';
const firstName = person.name ? (person.name.firstName || '') : '';
const lastName = person.name ? (person.name.lastName || '') : '';
const name = `${firstName} ${lastName}`.trim();

if (person.invoiceNinjaClientId || !email) {
    return null; // Already has ID or no email to map
}

msg.personId = person.id;
msg.method = "POST";
msg.url = "https://invoice.cosmoslab.dev/api/v1/clients";
msg.payload = {
    name: name,
    contacts: [
        {
            first_name: firstName,
            last_name: lastName,
            email: email,
            send_email: true
        }
    ]
};
msg.headers = {
    "X-Api-Token": env.get("CURBCLASS_INVOICENINJA_TOKEN"),
    "Content-Type": "application/json",
    "Accept": "application/json"
};

return msg;

const client = msg.payload && msg.payload.data;
const clientId = client ? (client.hashed_id || client.id) : '';

if (!clientId) {
    node.warn("CurbClass: Failed to create client in Invoice Ninja");
    return null;
}

msg.method = "PATCH";
msg.url = `${env.get("TWENTY_BASE_URL")}/rest/people/${msg.personId}`;
msg.payload = {
    invoiceNinjaClientId: clientId
};

return msg;

msg.method = "POST";
msg.url = env.get("TWENTY_BASE_URL") + "/rest/notes";
msg.payload = {
    title: msg.noteTitle,
    bodyV2: { markdown: msg.noteMarkdown || "" }
};
msg.headers = {
    "Authorization": "Bearer " + msg.twentyToken,
    "Host": msg.twentyHost,
    "Content-Type": "application/json"
};
return msg;

const note = msg.payload && msg.payload.data && msg.payload.data.createNote;
const noteId = note ? note.id : '';

if (!noteId) {
    msg.noteResult = {
        success: false,
        error: 'Note creation failed',
        details: msg.payload && msg.payload.errors
    };
    return [null, msg];
}

const targets = [];
if (msg.personId) {
    targets.push({ noteId: noteId, targetPersonId: msg.personId });
}
if (msg.opportunityId) {
    targets.push({ noteId: noteId, targetOpportunityId: msg.opportunityId });
}

if (targets.length === 0) {
    msg.noteResult = { success: true, noteId: noteId, linked: 0 };
    return [null, msg];
}

msg.noteId = noteId;
